"""
SAE J1939 Parameter Group Number (PGN) definitions.

Data sourced from SAE J1939-71 (Surface Vehicle Recommended Practice).
Each entry is a :class:`J1939PGNDef` namedtuple with the fields:

* ``pgn`` – PGN number (int)
* ``label`` – human-readable parameter group label (str)
* ``acronym`` – short acronym such as ``'EEC1'`` (str)
* ``data_length`` – payload length in bytes (int) or ``'variable'``
* ``default_priority`` – default CAN priority 0-7 (int) or ``None``
* ``spn_list`` – tuple of SPN numbers carried by this PGN
"""

from typing import NamedTuple, Optional, Tuple, Union


class J1939PGNDef(NamedTuple):
    pgn: int
    label: str
    acronym: str
    data_length: Union[int, str]
    default_priority: Optional[int]
    spn_list: Tuple[int, ...]


